patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
index d4a2fe5e37ef..f67e0992932e 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
@@ -750,6 +750,7 @@ static Instruction *shrinkInsertElt(CastInst &Trunc,
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
   if (Instruction *Result = commonCastTransforms(Trunc))
     return Result;
@@ -807,8 +808,8 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
     Value *X;
     const APInt *C1;
     Constant *C2;
-    if (match(Src, m_OneUse(m_Shr(m_Shl(m_Power2(C1), m_Value(X)),
-                                  m_ImmConstant(C2))))) {
+    if (match(Src, m_Shr(m_Shl(m_Power2(C1), m_Value(X)),
+                         m_ImmConstant(C2)))) {
       // trunc ((C1 << X) >> C2) to i1 --> X == (C2-cttz(C1)), where C1 is pow2
       Constant *Log2C1 = ConstantInt::get(SrcTy, C1->exactLogBase2());
       Constant *CmpC = ConstantExpr::getSub(C2, Log2C1);
@@ -816,15 +817,21 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
     }

     Constant *C;
-    if (match(Src, m_OneUse(m_LShr(m_Value(X), m_ImmConstant(C))))) {
-      // trunc (lshr X, C) to i1 --> icmp ne (and X, C'), 0
+    if (match(Src, m_LShr(m_Value(X), m_Constant(C)))) {
+      // trunc (lshr X, C) to i1
+      //   --> icmp slt X, 0            if shifting out the sign bit
+      //   --> icmp ne (and X, 1<<C), 0 otherwise
+      if (match(C, m_SpecificInt(APInt(SrcWidth, SrcWidth - 1))))
+        return new ICmpInst(ICmpInst::ICMP_SLT, X,
+                            Constant::getNullValue(X->getType()));
+
       Constant *One = ConstantInt::get(SrcTy, APInt(SrcWidth, 1));
       Value *MaskC = Builder.CreateShl(One, C);
       Value *And = Builder.CreateAnd(X, MaskC);
       return new ICmpInst(ICmpInst::ICMP_NE, And, Zero);
     }
-    if (match(Src, m_OneUse(m_c_Or(m_LShr(m_Value(X), m_ImmConstant(C)),
-                                   m_Deferred(X))))) {
+    if (match(Src, m_c_Or(m_LShr(m_Value(X), m_ImmConstant(C)),
+                          m_Deferred(X)))) {
       // trunc (or (lshr X, C), X) to i1 --> icmp ne (and X, C'), 0
       Constant *One = ConstantInt::get(SrcTy, APInt(SrcWidth, 1));
       Value *MaskC = Builder.CreateShl(One, C);
@@ -962,6 +969,7 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
   return Changed ? &Trunc : nullptr;
 }

+
 Instruction *InstCombinerImpl::transformZExtICmp(ICmpInst *Cmp,
                                                  ZExtInst &Zext) {
   // If we are just checking for a icmp eq of a single bit and zext'ing it
